func TestDefaultConfig(t *testing.T) {
	cfg := teamsmodel.DefaultConfig()

	// Verify default timeout
	if cfg.Timeout != "120s" {
		t.Errorf("DefaultConfig() timeout = %s, want 120s", cfg.Timeout)
	}

	// Verify default retry config
	if cfg.Retry.MaxAttempts != 3 {
		t.Errorf("DefaultConfig() retry.max_attempts = %d, want 3", cfg.Retry.MaxAttempts)
	}
	if cfg.Retry.Backoff != "exponential" {
		t.Errorf("DefaultConfig() retry.backoff = %s, want exponential", cfg.Retry.Backoff)
	}

	// Verify ports are configured
	if cfg.Ports == nil {
		t.Error("DefaultConfig() ports should not be nil")
	}
	if cfg.Ports != nil {
		if len(cfg.Ports.Inputs) != 1 {
			t.Errorf("DefaultConfig() input ports count = %d, want 1", len(cfg.Ports.Inputs))
		}
		// 2 outputs: "response" (JetStream) + "stream" (NATS fire-and-forget)
		if len(cfg.Ports.Outputs) != 2 {
			t.Errorf("DefaultConfig() output ports count = %d, want 2", len(cfg.Ports.Outputs))
		}
		if cfg.Ports.Inputs[0].Subject != "teams.request.>" {
			t.Errorf("DefaultConfig() input subject = %s, want teams.request.>", cfg.Ports.Inputs[0].Subject)
		}
		if cfg.Ports.Outputs[0].Subject != "teams.response.*" {
			t.Errorf("DefaultConfig() output subject = %s, want teams.response.*", cfg.Ports.Outputs[0].Subject)
		}
	}
}

// Helper function for case-insensitive substring matching
func containsIgnoreCase(s, substr string) bool {
	s = toLower(s)
	substr = toLower(substr)
	return contains(s, substr)
}

func toLower(s string) string {
	result := make([]byte, len(s))
	for i := 0; i < len(s); i++ {
		c := s[i]
		if c >= 'A' && c <= 'Z' {
			c += 'a' - 'A'
		}
		result[i] = c
	}
	return string(result)
}

func contains(s, substr string) bool {
	return len(s) >= len(substr) && (s == substr || len(substr) == 0 || indexSubstring(s, substr) >= 0)
}

func indexSubstring(s, substr string) int {
	n := len(substr)
	for i := 0; i <= len(s)-n; i++ {
		if s[i:i+n] == substr {
			return i
		}
	}
	return -1
}
